define(['jquery', 'core/ajax', 'core/notification', 'core/str'], function($, Ajax, Notification, Str) {
    "use strict";

    /**
     * Module de gestion du paiement Atouts Normandie.
     */
    return {
        init: function(paymentId, sesskey) {
            const modalHtml = `
                <div id="atouts-modal" style="display:none; position:fixed; z-index:1000; left:0; top:0; width:100%; height:100%; background:rgba(0,0,0,0.7); align-items:center; justify-content:center;">
                    <div style="background:white; padding:30px; border-radius:12px; max-width:450px; width:90%; text-align:center; box-shadow:0 10px 25px rgba(0,0,0,0.2);">
                        <h3 style="margin-top:0;">Scanner votre QR Code</h3>
                        <p style="color:#666;">Présentez votre QR Code Atouts Normandie devant votre caméra ou saisissez le numéro.</p>
                        <input type="text" id="atouts-qrcode-input" placeholder="Numéro du QR Code" autofocus
                               style="width:100%; padding:12px; margin:15px 0; border:2px solid #ddd; border-radius:6px; font-size:16px;">
                        <div id="atouts-status-area" style="margin:10px 0; min-height:20px; font-weight:bold;"></div>
                        <div style="display:flex; gap:10px; margin-top:20px;">
                            <button id="atouts-cancel" style="flex:1; padding:10px; background:#eee; border:none; border-radius:6px; cursor:pointer;">Annuler</button>
                            <button id="atouts-submit" style="flex:1; padding:10px; background:#007bff; color:white; border:none; border-radius:6px; cursor:pointer;">Valider</button>
                        </div>
                    </div>
                </div>
            `;

            $('body').append(modalHtml);

            // Ouvrir la modale au clic sur le bouton
            $('#btn-atouts-normandie').on('click', function(e) {
                e.preventDefault();
                $('#atouts-modal').css('display', 'flex');
                $('#atouts-qrcode-input').val('').focus();
                $('#atouts-status-area').text('').css('color', 'inherit');
            });

            // Fermer la modale
            $('#atouts-cancel').on('click', function() {
                $('#atouts-modal').hide();
            });

            // Soumission du QR Code
            $('#atouts-submit').on('click', function() {
                const qrCode = $('#atouts-qrcode-input').val().trim();
                if (!qrCode) return;

                const statusArea = $('#atouts-status-area');
                statusArea.text('Vérification en cours...').css('color', '#666');

                // Appel AJAX vers atouts_process.php
                $.ajax({
                    url: M.cfg.wwwroot + '/local/apsolu/payment/atouts_process.php',
                    method: 'POST',
                    data: {
                        paymentid: paymentId,
                        qrcode: qrCode,
                        sesskey: sesskey
                    },
                    success: function(response) {
                        if (response.success) {
                            statusArea.text(response.message).css('color', 'green');
                            setTimeout(function() {
                                window.location.reload(); // Recharge la page pour voir le nouveau prix
                            }, 1500);
                        } else {
                            statusArea.text(response.error).css('color', 'red');
                        }
                    },
                    error: function() {
                        statusArea.text('Erreur de communication avec le serveur.').css('color', 'red');
                    }
                });
            });

            // Permettre la validation avec la touche Entrée
            $('#atouts-qrcode-input').on('keypress', function(e) {
                if (e.which === 13) $('#atouts-submit').click();
            });
        }
    };
});
